function buildLocales() {
  const useLocales = Object.values(locales).reduce((acc, data) => {
    const localeVariants = countryLocaleVariants[data.code];
    if (localeVariants) {
      localeVariants.forEach((l) => {
        const entry = {
          ...data,
          code: l.code,
          name: l.name,
          files: [data.file, `${l.code}.json`]
        };
        delete entry.file;
        acc.push(entry);
      });
    } else {
      acc.push(data);
    }
    return acc;
  }, []);
  return useLocales.sort((a, b) => a.code.localeCompare(b.code));
}
const currentLocales = buildLocales();
const datetimeFormats = Object.values(currentLocales).reduce((acc, data) => {
  const dateTimeFormats = data.dateTimeFormats;
  if (dateTimeFormats) {
    acc[data.code] = { ...dateTimeFormats };
    delete data.dateTimeFormats;
  } else {
    acc[data.code] = {
      shortDate: {
        dateStyle: "short"
      },
      short: {
        dateStyle: "short",
        timeStyle: "short"
      },
      long: {
        dateStyle: "long",
        timeStyle: "medium"
      }
    };
  }
  return acc;
}, {});
const numberFormats = Object.values(currentLocales).reduce((acc, data) => {
  const numberFormatsArray = data.numberFormats;
  if (numberFormatsArray) {
    acc[data.code] = { ...numberFormatsArray };
    delete data.numberFormats;
  } else {
    acc[data.code] = {
      percentage: {
        style: "percent",
        maximumFractionDigits: 1
      },
      smallCounting: {
        style: "decimal",
        maximumFractionDigits: 0
      },
      kiloCounting: {
        notation: "compact",
        compactDisplay: "short",
        maximumFractionDigits: 1
      },
      millionCounting: {
        notation: "compact",
        compactDisplay: "short",
        maximumFractionDigits: 2
      }
    };
  }
  return acc;
}, {});
const pluralRules = Object.values(currentLocales).reduce((acc, data) => {
  const pluralRule = data.pluralRule;
  if (pluralRule) {
    acc[data.code] = pluralRule;
    delete data.pluralRule;
  }
  return acc;
}, {});

const config_i18n_46config_46ts_97aac619 = () => {
  return {
    availableLocales: currentLocales.map((l) => l.code),
    fallbackLocale: "en-US",
    fallbackWarn: true,
    missingWarn: true,
    datetimeFormats,
    numberFormats,
    pluralRules
  };
};

